import java.util.HashSet;
import java.util.Set;

public class Main {
    static boolean hasDuplicate(int[] numbers) {
        Set<Integer> seen = new HashSet<>();
        for (int num : numbers) {
            if (seen.contains(num)) {
                return true;
            }
            seen.add(num);
        }
        return false;
    }

    public static void main(String[] args) {
        int[] nums = {1, 2, 3, 4, 2};
        System.out.println(hasDuplicate(nums));
    }
}

static boolean hasPairBruteForce(int[] arr, int target) {
    for (int i = 0; i < arr.length; i++) {
        for (int j = i + 1; j < arr.length; j++) {
            if (arr[i] + arr[j] == target) {
                return true;
            }
        }
    }
    return false;
}

import java.util.HashSet;
import java.util.Set;

public class Main {
    static boolean hasPairHashing(int[] arr, int target) {
        Set<Integer> seen = new HashSet<>();
        for (int num : arr) {
            int complement = target - num;
            if (seen.contains(complement)) {
                return true;
            }
            seen.add(num);
        }
        return false;
    }

    public static void main(String[] args) {
        int[] arr = {8, 3, 15, 6, 2};
        System.out.println(hasPairHashing(arr, 9));
        System.out.println(hasPairHashing(arr, 100));
    }
}

